fn getuname(uid: uid_t) -> String {
    unsafe {
        let pw = getpwuid(uid);
        if pw.is_null() {
            return format!("{}", uid);
        }
        let name = (*pw).pw_name;
        let cstr = CStr::from_ptr(name);
        cstr.to_string_lossy().into_owned()
    }
}

fn getgname(gid: gid_t) -> String {
    unsafe {
        let gr = getgrgid(gid);
        if gr.is_null() {
            return format!("{}", gid);
        }
        let name = (*gr).gr_name;
        let cstr = CStr::from_ptr(name);
        cstr.to_string_lossy().into_owned()
    }
}

